import React, { useState } from "react";
import NftPreview from "./NftPreview";

const GeneratorForm = () => {
  const [description, setDescription] = useState("");
  const [style, setStyle] = useState("Digital Art");
  const [nftImages, setNftImages] = useState([]);

  const handleGenerate = async () => {
    // Simulate API call to generate images
    const generatedImages = [
      "path/to/image1.jpg", // Replace with dynamic generation
      "path/to/image2.jpg",
    ];
    setNftImages(generatedImages);
  };

  return (
    <div style={{ textAlign: "center", padding: "20px" }}>
      <input
        type="text"
        placeholder="Describe Your Image"
        value={description}
        onChange={(e) => setDescription(e.target.value)}
        style={{ padding: "10px", width: "60%", borderRadius: "5px", marginBottom: "10px" }}
      />
      <br />
      <select
        value={style}
        onChange={(e) => setStyle(e.target.value)}
        style={{ padding: "10px", borderRadius: "5px", marginBottom: "10px" }}
      >
        <option>Digital Art</option>
        <option>Abstract</option>
        <option>Realism</option>
      </select>
      <br />
      <button
        onClick={handleGenerate}
        style={{
          padding: "10px 20px",
          backgroundColor: "#00d1b2",
          color: "white",
          border: "none",
          borderRadius: "5px",
          cursor: "pointer",
        }}
      >
        GENERATE
      </button>
      <NftPreview images={nftImages} />
    </div>
  );
};

export default GeneratorForm;
